    for (auto& e : edges) {
        long long u = e[0], v = e[1], w = e[2];
        adj[u].push_back({v, w});
    }

    // Dijkstra's algorithm with state (node, switch_used)
    // switch_used is 0 or 1 (0: switch not used, 1: switch used)
