fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    use std::cmp::Ordering;
    use std::collections::BinaryHeap;

    let n = n as usize;
    let mut adj = vec![vec![]; n];
    for e in edges {
        let u = e[0] as usize;
        let v = e[1] as usize;
        let w = e[2];
        adj[u].push((v, w));
    }

    let mut dist = vec![vec![i64::MAX; 2]; n];
    dist[0][0] = 0;
    let mut pq = BinaryHeap::new();
    pq.push((0, 0, 0)); // (cost, node, switch_used)

